@@ -563,6 +563,19 @@ pub fn toPyValue(allocator: std.mem.Allocator, value: anytype) !PyValue {
         return .{ .list = list };
     }

+    // Tagged unions (IntResult, PyPowResult, etc.) - extract active field and convert
+    // This handles unions like IntResult{ .small = 5 } -> PyValue{ .int = 5 }
+    if (info == .@"union" and info.@"union".tag_type != null) {
+        // Get the active tag and extract the value
+        const tag = std.meta.activeTag(value);
+        inline for (info.@"union".fields) |field| {
+            if (tag == @field(std.meta.Tag(T), field.name)) {
+                const field_value = @field(value, field.name);
+                return try toPyValue(allocator, field_value);
+            }
+        }
+    }
+
     // Fallback: store as opaque pointer
     return .{ .ptr = @ptrCast(@constCast(&value)) };
 }

@@ -282,11 +282,12 @@ pub fn inferMethodCall(
         }
         // is_integer returns bool
         if (method_hash == IS_INTEGER_HASH) return .bool;
-        // __floor__, __ceil__, __trunc__, __round__ return int
+        // __floor__, __ceil__, __trunc__, __round__ return IntResult (union of i64/BigInt)
+        // Return .unknown so assertEqual uses assertEqualGeneric which handles unions via toPyValue
         if (method_hash == FLOOR_HASH or method_hash == CEIL_HASH or
             method_hash == TRUNC_HASH or method_hash == ROUND_HASH)
         {
-            return .{ .int = .bounded };
+            return .unknown;
         }
         // hex returns string
         if (method_hash == HEX_HASH) return .{ .string = .runtime };

@@ -392,6 +392,13 @@ fn genTupleUnpackLoop(self: *NativeCodegen, target: ast.Node, iter: ast.Node, bo
             try self.genExpr(iter);
             try self.emit(".items");
         }
+    } else if (iter == .name) {
+        // Variable with unknown type - use comptime check for .items field
+        // This handles cases where type inference doesn't return .list but codegen
+        // produced ArrayList (e.g., large string lists in methods)
+        try self.emit("blk_iter: { const __iter_val = ");
+        try self.genExpr(iter);
+        try self.emit("; break :blk_iter if (@typeInfo(@TypeOf(__iter_val)) == .@\"struct\" and @hasField(@TypeOf(__iter_val), \"items\")) __iter_val.items else __iter_val; }");
     } else {
         // Not a list type - iterate directly
         try self.genExpr(iter);
